var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……과연.","JPN":"……なるほど。","ENG":"...I see.","TWN":"……究竟。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"결국 자네는 시니어 코드를 사용해 시니어가 남긴 정보를 알아냈다는 건가?","JPN":"つまり、君はシニアコードを使用してシニアが残した情報を入手したということか。","ENG":"So in the end, you used the Senior Code and pulled the information he left behind?","TWN":"妳最後還是用Senior代碼查出Senior留下的情報了嗎？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"예. 정확하게는 전 세계적인 규모로 발생할 대균열 이상 현상에 관해서죠.","JPN":"はい。正確に言えば、全世界規模で発生する大亀裂異常現象の情報です。","ENG":"Yes. Specifically about the worldwide Grand Dimension Crevice anomalies.","TWN":"對，準確來說是關於規模遍及全世界的大峽谷異常現象。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"일정 시간 동안 여섯 지부의 대균열이 확산되고 나면.","JPN":"一定時間、6つの支部の大亀裂が拡大したら……","ENG":"After the six branches' Grand Dimension Crevices expand for a set time,","TWN":"六個分部的大峽谷在一定時間內擴散之後，"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그곳으로부터 뻗어 나온 침식 뿌리가 주변의 가능성을 닥치는 대로 빨아들일 거예요.","JPN":"そこから伸びてきた侵食の根が、周辺の可能性を手当たり次第吸い込みます。","ENG":"the roots stretching out from them will suck up all the possibilities nearby they can reach.","TWN":"從那裡延伸出的侵蝕根會任意吸取周圍的可能性。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 이상하군요. 만약 당신의 말 대로 전세계적인 침식 현상이 발생한다면…….","JPN":"しかし……もしその話通り、全世界的な侵食現象が発生するとしたら……","ENG":"Odd. If a global Counterside Effect is imminent as you say...","TWN":"但是很奇怪，如果照妳說的會發生遍及全世界的侵蝕現象……"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"어째서 해당 사실을 공표하지 않는 거죠?","JPN":"なぜその事実を発表しないのですか？","ENG":"why has it not been announced publicly?","TWN":"為什麼不公布這件事呢？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"시간이 급박한들, 민간인 피해는 확연히 줄 겁니다.","JPN":"時間が足りないとはいえ、民間人の被害は確実に抑えられます。","ENG":"Even if time is tight, civilian casualties would drop noticeably.","TWN":"就算時間緊迫，平民百姓的損害也會明顯減少。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"제가 사실을 공표해도 상부는 절 시니어의 부재를 노린 반동분자 정도로 여길 거예요.","JPN":"私が事実を公表したところで、上層部は私のことをシニアの不在を狙って反乱を起こそうとしていると思うはずです。","ENG":"Even if I went public, the higher-ups would brand me a reactionary exploiting the Senior's absence.","TWN":"即使我公布這件事，上級也只會把我當成窺伺Senior空缺的反動分子。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"당장 정보의 출처가 잭슨 씨라는 걸 입증하는데 얼마나 시간이 쓰일지 모를뿐더러…….","JPN":"そもそも、情報の出処がジャクソンさんということを証明するのに、どれだけの時間がかかるかも分からないし……","ENG":"Proving that Mr. Jackson is the source would eat up who knows how much time, and...","TWN":"現在要證明情報來源是傑森，不知道要花多久時間……"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"앞으로 일어날 전조 현상은 결국 특정 인물의 성장을 위한 시련이라고 해요.","JPN":"これから起こる前兆現象は、結局特定の人物を成長させるための試練だそうです。","ENG":"What is coming is framed as a trial to force the growth of a certain person.","TWN":"而且之後發生的前兆現象最終是對特定人物成長的考驗。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"인과를 틀어 그걸 거스르려 해봤자, 오히려 세상의 멸망을 앞당기는 셈이죠.","JPN":"因果を捻じ曲げて逆らおうとしても、世界の滅亡を早めることにしかなりません。","ENG":"Try to twist causality to fight it, and you only speed up the world's ruin.","TWN":"就算想扭轉因果反其道而行，反倒算是加速世界的滅亡。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"특정 인물이 누구인데?","JPN":"特定の人物って誰？","ENG":"And who is that certain person?","TWN":"特定人物是誰？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"늑대라고 적혀 있긴 했는데, 자세한 설명은 없어서 저도 잘…….","JPN":"オオカミって書かれているけど、詳しい説明はなくて……","ENG":"It said the Wolf, but there were no details, so I'm not sure...","TWN":"雖然上面寫的是狼，但沒有詳細說明，我也不清楚……"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어, 어쨌든! 챔버 쪽에 온 힘을 쏟아붓더라도 어떻게 될지 알 수 없다는 소리예요!","JPN":"と、とにかく！　チェンバーの方に全力を注いでも、どうなるか分からないってことです！","ENG":"A-anyway, it means even if we throw everything at Chamber, the outcome is unknown.","TWN":"總、總之！意思是就算在密室那邊傾注全力，也無法得知會怎麼樣！"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"과연, 이전 클리포트 게임과 비슷한 흐름이라고 생각하면 되겠군.","JPN":"なるほど。以前のクリフォトゲームと似たような流れだと思えばいいのだな。","ENG":"I see. Then it tracks with the flow we saw during the last Qliphoth Game.","TWN":"果然，應該可以想成是和先前的逆卡巴拉遊戲相似的進程。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐, 당장 허신이나 마왕 같은 놈들이 나온다면 다른 쪽을 걱정할 때가 아니긴 하지.","JPN":"まあ、今すぐ虚神や魔王のような奴らが出てくるとすれば、他を心配する余裕なんかないわね。","ENG":"Yeah, if a Hollow God or Demon Lord show up right now, we have bigger fish to fry than anything else.","TWN":"要是幻神或魔王之類的傢伙立刻出現，的確不是該擔心別人的時候。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 방법이 있어?","JPN":"なら、何か他に手があるの？","ENG":"But do we have a shot?","TWN":"但是有方法嗎？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"예전에 싸웠던 허신, 아니 리플레이서조차 우리 힘만으로는 버거운 상대였다고.","JPN":"前に戦った虚神……ううん、リプレイサーすらもアタシたちの力じゃ太刀打ちできなかったわ。","ENG":"Even the Hollow God we fought back then, or even the Replacer, was too much for our strength alone.","TWN":"以前戰鬥過的幻神，不，就連克隆部隊都是單憑我們的力量難以對付的對手。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그거라면 걱정 마세요. 다 방법이 있으니까!","JPN":"それなら心配いりません。手はあります！","ENG":"Then don't worry about that. There's a way!","TWN":"這點妳不用擔心，都有辦法！"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"다들, 화면을 집중해 주세요!","JPN":"皆さん、画面を見てください！","ENG":"Everyone, eyes on the screen!","TWN":"大家，請注意看畫面！"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이건?","JPN":"これは？","ENG":"That's...","TWN":"這是？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"로터스 시니어의 필체로군. 아무래도 어떤 장치의 설계도인 듯해.","JPN":"ロータスのシニアの筆跡だな。何かの装置の設計図のようだが？","ENG":"The Lotus Senior's handwriting. Looks like a schematic for some device.","TWN":"是洛德斯Senior的筆跡，似乎是某種裝置的設計圖。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"선로전환기는 이터니움 드라이브를 활용해 그림자의 부상 좌표를 전환하는 장치예요.","JPN":"線路転換器は、エタニウムドライブを活用してシャドウが浮上する座標を転換する装置です。","ENG":"The Track Switcher uses an Eternium Drive to alter the emergence coordinates of Shadows.","TWN":"線路轉換器是運用永恆之金驅動器，轉換暗影浮動座標的裝置。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이걸 사용하면 공간 좌표축을 뒤틀어 뿌리의 진격 속도를 최대한 늦출 수 있죠.","JPN":"これを使えば空間座標軸を捻じ曲げて、根が伸びる速度をできるだけ遅くすることができます。","ENG":"With it, we can twist the spatial axes and slow the roots' advance as much as possible.","TWN":"使用這個的話就能扭轉空間座標軸，最大限度減緩根部的進擊速度。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"시니어 이졸데가 잘 때 슬쩍… 이 아니라, 원만한 합의를 통해 공유 받았답니다!","JPN":"シニア・イゾルデが寝てる間にこっそり……じゃなくて、合意のもとに共有してもらいました！","ENG":"I kinda swiped it when Senior Isolde was asleep– I mean, she shared it with me when we reached a friendly agreement!","TWN":"趁Senior伊索德睡覺的時候偷偷…不，是透過圓滿的協議得到共享！"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"흐음… 척 보기에 아무렇게나 쓸 수 있는 물건은 아닌 것 같은데?","JPN":"へえー……見た感じ、簡単に使える物ではなさそうだけど？","ENG":"Hmm... Doesn't look like something you can just plop down and use.","TWN":"嗯哼…這看起來好像不是隨便就能用的東西耶？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"에이, 별거 없어요!","JPN":"いや～大したことありません！","ENG":"It's not a big deal.","TWN":"唉唷，沒什麼特別的！"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그냥 동력원으로 사용할 이터니움이 조금. 아니, 많이 필요하단 것 정도…?","JPN":"ただ、動力源になるエタニウムがちょっと……いや、たくさん必要なだけで……","ENG":"You just need a little– I mean, a lot of Eternium to power it...?","TWN":"就只是需要一點，不對，是需要很多用來做為動力來源的永恆之金…？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"과연, 세계를 지키기 위해 합중국의 자산을 빌려달라는 셈이군.","JPN":"なるほど。世界を守るために、合衆国の資産を貸してほしいということか。","ENG":"In other words, you're asking to borrow the States' assets to protect the world.","TWN":"果然，這等於是要我們借用合眾國的資產來守護世界。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 자네의 말을 믿기에 당장은 두 가지 문제가 있어.","JPN":"だが、君の話を信用するに当たって2つ問題がある。","ENG":"But if I am to take you at your word, two problems remain for now.","TWN":"但是要相信妳的話，目前有兩個問題。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"두, 두개나 있나요?","JPN":"2つも？","ENG":"T-two problems?","TWN":"有、有兩個嗎？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"우선 첫째. 챔버의 시니어는 어떻게 미래에 벌어질 일을 알고 있었는가.","JPN":"1つ目は、チェンバーのシニアはなぜ未来の出来事について知っていたのか。","ENG":"First, how did Chamber's Senior know future events?","TWN":"首先，第一個是密室的Senior怎麼知道未來會發生的事？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고, 둘째. 임계 질량 이상의 이터니움이 모이면 그 에너지가 차원계면을 융해시키지.","JPN":"2つ目は、臨界質量を超えるエタニウムが集まると、そのエネルギーが次元界面を融解させてしまうこと。","ENG":"Second, once Eternium exceeds critical mass, its energy melts the dimension surface.","TWN":"然後第二個是，超過臨界質量的永恆之金聚集時，其能量會融解次元界面。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"유감스럽게도 설계도를 살폈을 때 문제를 해결할 요소는 보이지 않는군.","JPN":"残念ながら設計図を見た感じ、その問題を解決できそうな要素は見当たらないな。","ENG":"Unfortunately, I don't see anything in the blueprint that addresses that.","TWN":"遺憾的是，我查看設計圖的時候，沒看到能解決問題的要素。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마 말이 맞아. 차원계면은 고사하고, 그림자들을 막는데 이정도 출력으론 어림없어.","JPN":"おばんさんの言う通りよ。この程度の出力じゃ次元界面はおろか、シャドウも阻止できないわ。","ENG":"Maria is right. Forget the dimension surface, this output won't even be enough to stop Shadows.","TWN":"阿姨說得沒錯，姑且不論次元界面，單憑這點輸出根本不可能ˊ阻擋暗影。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"시니어 잭슨이랬나? 그 사람. 준비가 너무 허술한 거 아니야?","JPN":"シニア・ジャクソンって言ったっけ？　準備が甘すぎるんじゃないの？","ENG":"Senior Jackson, was it? Sounds like his prep was awfully sloppy.","TWN":"是Senior傑森嗎？那個人準備未免太馬虎了吧？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"잭슨 씨는 허술하지 않아요! 그 문제라면 제대로 해결할 수 있는 걸요!","JPN":"ジャクソンさんは甘くありません！　それなら、ちゃんと解決できます！","ENG":"Mr. Jackson is not sloppy. And that issue can be solved properly!","TWN":"傑森一點都不馬虎！那個問題應該能順利解決！"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그건, 그…….","JPN":"それは、その……","ENG":"That's, uh...","TWN":"那、那個……"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"북방합의체의 힘을 빌리면, 어떻게든…….","JPN":"北方合意体の力を借りれば、なんとか……","ENG":"If we borrow the power of the Northern Union, somehow...","TWN":"要是借助北方和議會的力量，無論如何……"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"북방합의체? 설마 나라 전체가 관리거부지역인 녀석들을 말하는 거야?","JPN":"北方合意体？　まさか国全体が管理拒否地域になっているやつらのこと？","ENG":"The Northern Union? You mean the nation that's entirely an Anti-Administration Zone?","TWN":"北方和議會？難道是指整個國家都是拒絕管理地區的傢伙嗎？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이봐, 이쪽은 지금 그쪽이 던진 화두에 모인 거 몰라?","JPN":"あのね、こっちは今そっちの話を聞くために集まってやったのよ。","ENG":"Hey, don't you get it? We're here because of the issue your side threw out.","TWN":"喂，妳不知道這邊現在都聚焦在你提出的話題上嗎？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"세상이 멸망한다는 건 둘째 치고, 적대세력의 힘을 빌린다는 게 무슨 소린데?","JPN":"世界が滅亡する件はともかく、敵勢力の力を借りようだなんてどういうつもり？","ENG":"End of the world or not, why are we borrowing power from an enemy faction?","TWN":"先不說世界滅亡這件事，說要借助敵對勢力是什麼意思？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"좋아, 협력하지.","JPN":"いいだろう。協力しよう。","ENG":"All right. We will cooperate.","TWN":"很好，合作吧。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"정말요? 앗싸-!","JPN":"本当ですか？　やったー！","ENG":"Really? Awesome!","TWN":"真的嗎？好耶…！"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마. 내 말 들었어? 저거 누가 봐도 수상하잖아!","JPN":"おばさん、アタシの話聞いてた？　どう見ても怪しいでしょ！","ENG":"Maria, did you hear me? That set-up screams suspicious!","TWN":"阿姨，妳有聽到我的話嗎？那個任誰看都很可疑！"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"단, 이쪽은 현장 상황에 맞춰 임의로 움직이겠네.","JPN":"ただし、こちらは現場の状況に合わせて自己判断で動く。","ENG":"On one condition. We act on our own judgment to match the situation on the ground.","TWN":"但是我們這邊會根據現場情況任意行動。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"부차적인 내용은 이동하면서 나누지.","JPN":"その他については移動しながら話すとしよう。","ENG":"We will handle the side details en route.","TWN":"次要的內容就邊移動邊聊吧。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"넵! 감사합니다! 완전 멋진 중장님!!","JPN":"はいっ！　ありがとうございます、中将さん最高！！","ENG":"Got it! Thank you, Lieutenant General! You're awesome!!","TWN":"是！謝謝！超級帥氣的中將！！"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"허…….","JPN":"はあ……","ENG":"Whoa...","TWN":"呃……"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"제정신이야, 아줌마? 함정일지도 모르는데 이걸 덜컥 받아들이면 어떡해?","JPN":"すんなり引き受けちゃうなんて、おばさん正気なの？　罠かもしれないわよ。","ENG":"Are you out of your mind, Maria? What if it's a trap and you just said yes?","TWN":"阿姨，妳瘋了嗎？這也許是個陷阱，妳怎麼能馬上就接受？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨의 말이 맞습니다, 사령관님.","JPN":"シルビアさんの言う通りです、司令官。","ENG":"Ms. Sylvia has a point, Commander.","TWN":"希爾維亞說得沒錯，司令官。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"앞선 대화가 사실이라 한들, 검은 평의회와의 협력이 저흴 정치적으로 내몬 것처럼…….","JPN":"先の話が事実だとしても、黒い評議会との協力が僕たちを政治的に危うい立場にしたように……","ENG":"Even if the earlier briefing is true, working with the Dark Council already put us in a political corner...","TWN":"就算之前的談話是事實，但和黑暗評議會合作就像把我們推向政治……"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"합중국이 북방합의체와 협력하게 된다면 정계에 커다란 파장을 몰고 올 겁니다.","JPN":"合衆国が北方合意体と手を組むとなれば、政界もざわつくはずです。","ENG":"If the States partner with the Northern Union, the shockwave through politics will be massive.","TWN":"要是合眾國和北方和議會合作的話，就會在政界掀起軒然大波。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"동의하네. 불확실한 정보를 토대로 한 작전은 매번 고생길이 훤했지.","JPN":"同意見だ。不確かな情報をベースにした作戦では、毎回苦労させられてきた。","ENG":"Agreed. Every operation built on uncertain intel turned into a slog.","TWN":"我贊同，以不確實的情報為基礎進行的作戰每次都很艱辛。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 그걸 아는 사람이 왜 이래?","JPN":"知っててなんで引き受けたの？","ENG":"Then why are you like this if you know that?","TWN":"等等，妳明知道為什麼還這麼做？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"세상 어느 미치광이도 합중국, 그것도 대통령을 상대로 블러핑을 걸진 않아.","JPN":"合衆国、しかも大統領相手にはったりをかますような狂人はそうそういない。","ENG":"No lunatic on earth would bluff the States, much less the President.","TWN":"世上沒有任何一個瘋子會對合眾國，而且還是對總統吹噓。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"관리국 공인 카운터가 본인 얼굴을 내걸었으니 사기를 친다면 오히려 논리 정연했겠지.","JPN":"管理局公認カウンターが、自分の顔と名をかけたのだ。騙すつもりならもっと理路整然と説明しただろう。","ENG":"And if an Official Administration Counter showed her face and still tried to con us, that would be a pretty coherent scam.","TWN":"既然管理局公認制裁者賭上了自己的名譽，如果行騙的話，反而會有條有理。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"거기에 이번 일이 북방합의체와 연관 있다면 시니어가 미래를 봤다는 말도 그럴듯해.","JPN":"それに今回の件が北方合意体と関わっているなら、シニアが未来を見たということも合点がいく。","ENG":"If this ties to the Northern Union, the claim that a Senior foresaw the future also tracks.","TWN":"而且要是這次的事和北方和議會有關，Senior看見未來的說法也有道理。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"실제로 합의체는 예지능력을 지닌 인공 카운터를 만들어냈다는 소문이 있으니 말이야.","JPN":"実際、合意体が予知能力を持つ人工カウンターを生み出したという噂もあるしな。","ENG":"There are even rumors the Northern Union created artificial Counters with precognition.","TWN":"其實有傳聞說和議會打造出具有預知能力的公認制裁者。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 아줌마 말 대로 아까 예니카란 녀석이 말했던 게 진짜라고 치자.","JPN":"おばさんの言う通り、さっきのイェニカってやつの話が本当だとして。","ENG":"Fine. Say what that Yanikka girl said is true.","TWN":"好，如同阿姨說的，就算剛才耶妮卡那傢伙說的是真的。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하지만… 진실 속의 거짓이라는 말도 있잖아?","JPN":"……真実の中の嘘ってこともあるでしょ？","ENG":"But... Ever hear of a lie nested inside the truth?","TWN":"但是…不是也有句話叫真相中的謊言嗎？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"챔버 관리국이랑은 무관하게, 북방합의체가 판 함정이면 어떡해?","JPN":"チェンバー管理局とは関係なく、北方合意体が仕掛けた罠だったらどうするの？","ENG":"What if this has nothing to do with the Chamber Administration and is a trap set by the Northern Union?","TWN":"如果和密室管理局無關，是北方和議會挖的陷阱怎麼辦？"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그걸 알기 위해서라도 움직여야지.","JPN":"それを確認するためにも動かねば。","ENG":"That is exactly what we need to find out.","TWN":"就算是為了搞清楚這件事，也應該採取行動。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"어느 쪽이든, 북방합의체의 영토에 갈 명분이 생겼으니 손해보는 장사는 아니야.","JPN":"どっちにしろ、北方合意体の領土に向かう口実ができたわけだ。損はない。","ENG":"Either way, we now have cause to enter the Northern Union's territory. That alone is not a losing play.","TWN":"不管怎麼樣，既然有了前往北方和議會領土的名分，這也不是賠本生意。"},"stage":{"bg":"ROOM_03","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"북방합의체의 영토권인 그라운드 제로는 나와 제이나가 맡지.","JPN":"北方合意体の領土圏であるグラウンド・ゼロは私とジェイナが担当しよう。","ENG":"Ground Zero of the Northern Union territory will be mine and Jaina's.","TWN":"北方和議會領土圈的Ground Zero就由我和婕娜負責。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네들은 챔버 대균열로 이동해, 앞으로 일어날 이상 현상에 대비하도록.","JPN":"君たちはチェンバーの大亀裂へ向かい、これから起こる異常現象に備えたまえ。","ENG":"The rest of you, move to Chamber's Grand Dimension Crevice and prepare for the anomalies to come.","TWN":"你們移動到密室大峽谷，以備之後會發生的異常現象。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"唉……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"조마조마했네. 저쪽 사령관이 말이 통하는 사람이라 다행이야.","JPN":"ハラハラした。あっちの司令官が話の通じる人でよかったよ。","ENG":"That had me sweating. Thank goodness their commander is reasonable.","TWN":"真是提心吊膽，幸好那裡的司令官是個說得通的人。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"와, 와아~.","JPN":"わ、わあ～","ENG":"W-wow...","TWN":"哇、哇啊～"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"박수치지 마세요. 어렴풋이 아는 걸로 설명하느라 얼마나 진땀 뺐는지 알아요?","JPN":"拍手やめてください。自分でもよく分かってないことを説明するの大変だったんですから！","ENG":"Don't clap. Do you know how hard it is to explain when you only half know?","TWN":"不要鼓掌，妳知道為了用隱約知道的東西來說明，我費了多少工夫嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"애당초, 왜 합의체 소속도 아닌 제가 펠릭스의 계획을 설명하는 건가요?","JPN":"そもそも、なんで合意体所属でもない私がフェリックスの計画を説明しないといけないんですか？","ENG":"And why am I, someone not even part of the Northern Union, explaining Felix's plan?","TWN":"為什麼會是由根本不是隸屬於和議會的我來說明緋莉克絲的計畫？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"그, 그야 전 말더듬도 심하고 나이도 어리니까요.","JPN":"そ、それは、私はどもりも酷いし、子どもですから。","ENG":"B-because I stutter a lot and I'm young.","TWN":"那、那是因為我說話嚴重結巴，年紀又小。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"제가 합의체를 대표하는 것보다… 과, 관리국 공인인 예니카의 말이 더 설득력 있을 거예요.","JPN":"私が合意体を代表して話すより……か、管理局公認カウンターのイェニカが話した方が、もっと説得力があります。","ENG":"Rather than me speaking for the Northern Union, a-an Official Administration Counter like you is more convincing.","TWN":"比起由我來代表和議會…管、管理局公認的耶妮卡說的話應該更有說服力。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L24_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"폭실이도 그렇게…! 생각, 한데요.","JPN":"モコも、そう！　思う……ですって。","ENG":"Fluffox...! Thinks so too.","TWN":"福實也是…！這樣想的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"에휴, 됐어요. 지난 일로 이래라저래라 해봤자 변하는 것도 없고.","JPN":"はあ、もういいです。過ぎたことをどうこう言っても意味ないし。","ENG":"Ugh, forget it. What's done is done, and yelling about the past changes nothing.","TWN":"唉唷，算了，就算拿過去的事說長道短也不會有任何改變。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그럼-, 이제 저희도 챔버 대균열로 향하면 되죠?","JPN":"じゃあ、私たちもこれからチェンバーの大亀裂に向かえばいいんですね？","ENG":"So, now we head for Chamber's Grand Dimension Crevice, right?","TWN":"那麼，我們現在也可以去密室大峽谷了吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹. 컹.","JPN":"コン、コン。","ENG":"Arf. Arf.","TWN":"汪、汪。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_03"},{"id":"L30_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"웬일로 두 번 짖네? 얘가 뭐래요?","JPN":"2回鳴くなんて珍しい。今はなんて言ったんですか？","ENG":"Two barks, huh. What does that mean?","TWN":"怎麼會叫兩次？牠說什麼？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"<color=#ffd34c>전부 설명해줬는데 알아먹지도 못하네.</color>","JPN":"<color=#ffd34c>全部説明したのにまだ理解できないのかよ。</color>","ENG":"<color=#ffd34c>Explained everything and she still doesn't get it.</color>","TWN":"<color=#ffd34c>都已經全部說明了，還是聽不懂啊。</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"<color=#ffd34c>뇌는 장식이냐?</color>","JPN":"<color=#ffd34c>その脳みそは飾りか？</color>","ENG":"<color=#ffd34c>Is your brain just for show?</color>","TWN":"<color=#ffd34c>腦袋是拿來裝飾的嗎？</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"…래요!","JPN":"……ですって！","ENG":"...Is what Fluffox is saying!","TWN":"…牠是這樣說的！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_03"},{"id":"L40_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"움직이지 마. 한쪽 발만 잘릴 거 양쪽 다리 다 잘린다?","JPN":"足1本で済ませたいなら動くんじゃないよ。","ENG":"Don't you move. Keep it up and you lose both legs, not just one.","TWN":"不要動，本來只要砍掉一隻腳，現在兩隻腳都要砍掉囉？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"포, 폭실이 괴롭히지 마세요오…!","JPN":"モ、モコをいじめないでくださいぃ……！","ENG":"P-please don't bully Fluffox...!","TWN":"不、不要欺負福實…！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"그리고, 포, 폭실이가 이상한 소리를 한 건 아니에요. 저흰 대균열로 갈 필요 없어요.","JPN":"それに、モ、モコは変なことを言ったわけじゃありません。私たちは大亀裂に行かなくてもいいんです。","ENG":"A-and what it said wasn't wrong. We don't need to go to the Grand Dimension Crevice.","TWN":"而且，福、福實沒有說奇怪的話，我們不需要去大峽谷。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"잊은 거 아니죠? 이터니움으로만 선로전환기를 가동시키면 차원계면이 녹아내린다고요.","JPN":"忘れてませんよね？　エタニウムだけで線路転換器を稼働させたら、次元界面が溶けちゃいます。","ENG":"Remember? If the Track Switcher runs on Eternium alone, the dimension surface melts.","TWN":"妳沒有忘記吧？只要用永恆之金啟動線路轉換器，次元界面就會融化。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"그걸 방지하기 위해서라도, 저흰 이터니움의 에, 에너지 응집을 억제해줄 물건을 가져와야 해요.","JPN":"それを防ぐために、私たちはエタニウムのエ、エネルギー凝集を抑制してくれるものを探さないといけません。","ENG":"To prevent that, we need to bring something that suppresses Eternium's energy concentration.","TWN":"為了防止這種情況，我們要拿能抑制永恆之金能量凝聚的東西回來。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그런 물건을 어디서 찾는데요?","JPN":"そんなものがどこにあるんですか？","ENG":"And where do we find that?","TWN":"要在哪裡找那種東西？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"포, 폭실아. 어디였지?","JPN":"モ、モコ。どこだっけ？","ENG":"F-Fluffox, where was it again?","TWN":"福、福實，在哪裡？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L1_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"아…! 맞다!","JPN":"あ……！　そうだったね！","ENG":"Ah...! Right!","TWN":"啊…！對！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"여, 여기서 북동쪽.","JPN":"こ、ここから北東にある……","ENG":"I-it's northeast of here.","TWN":"這、這裡的東北方。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"<color=#ffd34c>시린그라드</color>로 가야해요…!!","JPN":"<color=#ffd34c>シリングラード</color>に行きます……！！","ENG":"We have to go to <color=#ffd34c>Ciringrad</color>...!!","TWN":"我們必須去<color=#ffd34c>錫林格勒</color>…！！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};